  syncHeaderOffset();
  if (!searchRowRef.value) {
    return;
  }

  searchRowHeight.value = searchRowRef.value.offsetHeight;
  const rowRect = searchRowRef.value.getBoundingClientRect();
  searchInitialTop = window.scrollY + rowRect.top;
}

function onScroll() {
  const headerHeightRaw = getComputedStyle(document.documentElement).getPropertyValue('--header-height');
  const headerHeight = Number.parseInt(headerHeightRaw, 10) || 64;
  const pinThreshold = searchInitialTop - headerHeight - 30;
  isSearchPinned.value = window.scrollY >= pinThreshold;
}

function onResize() {
  computeSearchMetrics();
  onScroll();
}

onMounted(async () => {
  await nextTick();
  computeSearchMetrics();
  onScroll();
  window.addEventListener('scroll', onScroll, { passive: true });
  window.addEventListener('resize', onResize);
});

onBeforeUnmount(() => {
  window.removeEventListener('scroll', onScroll);
  window.removeEventListener('resize', onResize);
});
</script>

